import { describe, expect, it } from '@a0n/gnosis/test';
import { BettyCompiler } from '../betty/compiler';
import { GnosisEngine } from './engine';
import { GnosisRegistry } from './registry';
import { loadGnosisWorkerRuntime } from './worker-runtime';
import type { SyncHandler } from './compiled-topology';

function makeRegistry(): GnosisRegistry {
  const registry = new GnosisRegistry();
  registry.register('Step', async (payload, props) => {
    const delta = Number.parseInt(props.delta ?? '1', 10);
    return (payload as number) + delta;
  });
  registry.register('Forker', async (payload) => [payload, payload]);
  registry.register('Left', async (payload) => (payload as number) + 2);
  registry.register('Right', async (payload) => (payload as number) + 5);
  registry.register('Sink', async (payload) => payload);
  return registry;
}

describe('GnosisWorkerRuntime', () => {
  const compiler = new BettyCompiler();

  it('loads native control-plane metrics once and executes compiled GG hot path', async () => {
    const registry = makeRegistry();
    const { ast } = compiler.parse(`
      (seed:Forker)-[:FORK]->(left:Left|right:Right)
      (left|right)-[:FOLD]->(sink:Sink)
    `);
    if (!ast) throw new Error('expected AST');

    const { runtime, nativeSnapshot } = await loadGnosisWorkerRuntime({
      ast,
      registry,
      fingerprint: 'worker-runtime-fold-test',
    });
    const result = await runtime.execute(10);

    expect(result.payload).toEqual({ left: 12, right: 15 });
    expect(result.nativeControlPlane).toBe(true);
    expect(nativeSnapshot?.edgesProcessed).toBe(2);
    expect(runtime.hasForks).toBe(true);
  });

  it('keeps worker hot execution faster than interpreted engine on a linear topology', async () => {
    const registry = makeRegistry();
    const { ast } = compiler.parse(`
      (a:Step { delta: "1" })-[:PROCESS]->(b:Step { delta: "2" })
      (b)-[:PROCESS]->(c:Step { delta: "3" })
      (c)-[:PROCESS]->(d:Step { delta: "4" })
    `);
    if (!ast) throw new Error('expected AST');

    const engine = new GnosisEngine(registry);
    const { runtime } = await loadGnosisWorkerRuntime({
      ast,
      registry,
      fingerprint: 'worker-runtime-linear-bench',
      nativeControlPlane: false,
    });

    const iterations = 250;
    await engine.executeWithResult(ast, 0);
    await runtime.execute(0);

    const engineStart = performance.now();
    for (let i = 0; i < iterations; i++) {
      await engine.executeWithResult(ast, i);
    }
    const engineMs = performance.now() - engineStart;

    const workerStart = performance.now();
    for (let i = 0; i < iterations; i++) {
      await runtime.execute(i);
    }
    const workerMs = performance.now() - workerStart;

    expect(workerMs).toBeLessThan(engineMs);
  });

  it('uses sync handler overrides for fork/fold worker hot paths', async () => {
    const registry = new GnosisRegistry();
    const asyncFallback = async () => {
      throw new Error('sync override was not selected');
    };
    registry.register('Forker', asyncFallback);
    registry.register('Left', asyncFallback);
    registry.register('Right', asyncFallback);
    registry.register('Sink', asyncFallback);

    const syncHandlerOverrides = new Map<string, SyncHandler>([
      ['Forker', (payload) => [payload, payload]],
      ['Left', (payload) => (payload as number) + 2],
      ['Right', (payload) => (payload as number) + 5],
      ['Sink', (payload) => payload],
    ]);
    const { ast } = compiler.parse(`
      (seed:Forker)-[:FORK]->(left:Left|right:Right)
      (left|right)-[:FOLD]->(sink:Sink)
    `);
    if (!ast) throw new Error('expected AST');

    const { runtime } = await loadGnosisWorkerRuntime({
      ast,
      registry,
      fingerprint: 'worker-runtime-sync-fork-fold-test',
      nativeControlPlane: false,
      syncHandlerOverrides,
    });
    const result = await runtime.execute(10);

    expect(result.payload).toEqual({ left: 12, right: 15 });
    expect(result.handlerCalls).toBe(4);
    expect(result.nativeControlPlane).toBe(false);
  });
});
